import { Alchemy, Network } from 'alchemy-sdk';
import { useEffect, useState } from 'react';
import "./styles.css";


import './App.css';

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};


// In this week's lessons we used ethers.js. Here we are using the
// Alchemy SDK is an umbrella library with several different packages.
//
// You can read more about the packages here:
//   https://docs.alchemy.com/reference/alchemy-sdk-api-surface-overview#api-surface
const alchemy = new Alchemy(settings);

function App() {
  const [blockNumber, setBlockNumber] = useState();
  const [blockInfo, setBlockInfo] = useState();
  const [blockWithTxs, setBlockWithTxs] = useState();
  const [txReceipts, setTxReceipts] = useState([]);

  useEffect(() => {
    async function fetchData() {
      //Block number
      const number = await alchemy.core.getBlockNumber();
      setBlockNumber(number);

      //Block info
      setBlockInfo(await alchemy.core.getBlock(number));

      //Block with full transaction objects
      const fullBlock = await alchemy.core.getBlockWithTransactions(number);
      setBlockWithTxs(fullBlock);

      //Fetch each transaction receipt
      const receipts = await Promise.all(
        fullBlock.transactions.slice(0, 10).map(
          (tx) => alchemy.core.getTransactionReceipt(tx.hash)
        )
      );
      setTxReceipts(receipts);
    }

    fetchData();
  }, []);

 return (
    <div className="etherscan-container">
      <h1 className="etherscan-title">Block #{blockNumber}</h1>

      <div className="block-card">
        <h2>Block Summary</h2>
        <table className="info-table">
          <tbody>
            <tr>
              <td>Block Number:</td>
              <td>{block.number}</td>
            </tr>
            <tr>
              <td>Timestamp:</td>
              <td>{new Date(block.timestamp * 1000).toLocaleString()}</td>
            </tr>
            <tr>
              <td>Miner:</td>
              <td className="mono">{block.miner}</td>
            </tr>
            <tr>
              <td>Hash:</td>
              <td className="mono">{block.hash}</td>
            </tr>
            <tr>
              <td>Parent Hash:</td>
              <td className="mono">{block.parentHash}</td>
            </tr>
            <tr>
              <td>Gas Used:</td>
              <td>{block.gasUsed.toString()}</td>
            </tr>
            <tr>
              <td>Gas Limit:</td>
              <td>{block.gasLimit.toString()}</td>
            </tr>
            <tr>
              <td>Difficulty:</td>
              <td className="mono">{block.difficulty}</td>
            </tr>
            <tr>
              <td>Transactions:</td>
              <td>{block.transactions.length}</td>
            </tr>
          </tbody>
        </table>
      </div>

      <div className="block-card">
        <h2>Transactions</h2>

        <table className="tx-table">
          <thead>
            <tr>
              <th>Hash</th>
              <th>From</th>
              <th>To</th>
              <th>Value (ETH)</th>
            </tr>
          </thead>
          <tbody>
            {block.transactions.slice(0, 20).map((tx) => (
              <tr key={tx.hash}>
                <td className="mono hash">{tx.hash}</td>
                <td className="mono">{tx.from}</td>
                <td className="mono">{tx.to || "Contract creation"}</td>
                <td>
                  {(Number(tx.value) / 1e18).toFixed(4)}
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {block.transactions.length > 20 && (
          <p className="note">
            Showing first 20 transactions of {block.transactions.length}.
          </p>
        )}
      </div>
    </div>
  );
}

export default App;
